H, M = map(int, input().split())
T = H * 60 + M
print('Yes' if 6 * 60 + 30 <= T <= 9 * 60 or 9 * 60 + 50 <= T <= 10 * 60 or 10 * 60 + 50 <= T <= 11 * 60 or 11 * 60 + 50 <= T <= 12 * 60 or 12 * 60 + 50 <= T <= 13 * 60 + 50 or 14 * 60 + 40 <= T <= 14 * 60 + 50 or 15 * 60 + 40 <= T <= 15 * 60 + 50 or 16 * 60 + 40 <= T <= 22 * 60 + 50 else 'No')